---调用app事件触发接口
---@param type number 事件类型
---@param params string 自定义参数
function ClientHelper.onAppActionTrigger(type, params)
    params = params or ""
    print("[ClientHelper.onAppActionTrigger][" .. type .. "] params=" .. params)
    HostApi.onAppActionTrigger(type, params)
end

---使用key-value的数据调用app方法
---@param name string 调用app的方法名称
---@param params table 方法自定义参数
function ClientHelper.callAppDataFunction(name, params)
    local result = params or {}
    result.functionName = name
    local data = DataBuilder.new():fromTable(result):getData()
    ClientHelper.onAppActionTrigger(10000, data)
end

---使用Json的数据调用app方法
---@param name string 调用app的方法名称
---@param params table 方法自定义参数
function ClientHelper.callAppJsonFunction(name, params)
    local result = params or {}
    result.functionName = name
    ClientHelper.onAppActionTrigger(10001, json.encode(result))
end

